        context: &ParserContext,
        parser: &mut Parser,
    ) -> Result<Self, ParseError> {
        // Parse the optional container name.
        let name = if let Ok(name) = parser.try_parse(|p| ContainerName::parse(p)) {
            name
        } else {
            ContainerName::none()
        };

        // Parse the container condition.
        let condition = QueryCondition::parse(context, parser, FeatureType::Container)?;
        let flags = condition.feature_flags();

        Ok(ContainerCondition {
            name,
            condition,
            flags,
        })
    }

    /// Returns whether the container condition matches a given element's container
    /// against a given stylist.
    pub fn matches<E>(
        &self,
        stylist: &Stylist,
        element: E,
        container_size_query: &mut ContainerSizeQuery,
    ) -> bool
    where
        E: TElement,
